//! A mock runtime executor for [QueryPlan].
//!
//! Executes the query plan exactly as written, with no access to the IDL, against
//! a set of in-memory SQLite pools. Intended to test the [QueryPlan] generated by the planner,
//! not necessarily the runtimes actual execution semantics:
//! - Does not chunk large spreads.
//! - Does not support partial failures. If any part of the plan fails, the whole
//!   plan fails. In the actual runtime, dependent steps will not execute, with the plan
//!   continuing where it can.
//! - Any missing value for a key is a hard failure

use orm::query::plan::{
    Database, DatabaseKind, JoinKeys, KeySegment, MapCardinality, Mapping, Query, QueryPlan,
    SqlArg, ValueArg,
};
use serde_json::{Map, Value, json};
use sqlx::{Column, Row, SqlitePool, ValueRef};

use crate::common::setup::MockStorage;

pub struct QueryExecutor<'a> {
    plan: &'a QueryPlan<'a>,
    params: Map<String, Value>,
    storage: &'a MockStorage,
    body: Value,
}

impl<'a> QueryExecutor<'a> {
    pub async fn execute(
        plan: &'a QueryPlan<'a>,
        params: Map<String, Value>,
        storage: &'a MockStorage,
    ) -> Value {
        Self {
            plan,
            params,
            storage,
            body: Value::Null,
        }
        ._execute()
        .await
    }

    async fn _execute(mut self) -> Value {
        for stage in &self.plan.stages {
            for step in &stage.steps {
                let result = &step.result;
                match &step.query {
                    Query::Sql {
                        database,
                        sql,
                        arguments,
                        shard,
                        mapping,
                    } => {
                        let rows = self.sql_step(database, sql, arguments, shard, result).await;

                        attach_rows(&mut self.body, result, mapping, rows);
                    }
                    Query::Key {
                        database,
                        segments,
                        shard,
                    } => self.key_step(result, database, segments, shard),
                    Query::Synthesize {
                        fields,
                        cardinality,
                    } => self.synthesize_step(result, fields, *cardinality),
                    Query::Tag { fields } => self.tag_step(result, fields),
                }
            }
        }

        self.body
    }

    async fn sql_step(
        &mut self,
        database: &Database<'_>,
        sql: &str,
        arguments: &[SqlArg<'_>],
        shard: &[(&str, SqlArg<'_>)],
        result: &[&str],
    ) -> Vec<Value> {
        let name = database.name;
        let Self {
            params,
            storage,
            body,
            ..
        } = self;

        // A `Spread` binding or shard value collects its field across the parents of this
        // step's own result path; the empty parent path for a root spread collects at the root.
        let parents = match result.split_last() {
            Some((_, parents)) => parents,
            None => &[],
        };

        match &database.kind {
            DatabaseKind::D1 => {
                let pool = storage.d1.get(name).expect("D1 binding to exist in tests");

                run_sql(sql, arguments, params, body, parents, pool).await
            }
            DatabaseKind::DurableObject => {
                let pools = storage
                    .durable
                    .get(name)
                    .expect("Durable binding to exist in tests");

                let fields = shard.iter().map(|(f, _)| *f).collect::<Vec<_>>();

                let mut rows = Vec::new();
                for tuple in shard_tuples(shard, params, body, parents) {
                    let pool = pools.get(&tuple).expect("Shard to exist in tests");

                    for mut row in run_sql(sql, arguments, params, body, parents, pool).await {
                        if let Value::Object(map) = &mut row {
                            for (field, value) in fields.iter().zip(&tuple) {
                                // Tag each row with the shard values that produced it.
                                map.insert(field.to_string(), value.clone());
                            }
                        }
                        rows.push(row);
                    }
                }
                rows
            }
            other => panic!("unsupported database {other:?}"),
        }
    }

    fn synthesize_step(
        &mut self,
        result: &[&str],
        fields: &[(&str, ValueArg<'_>)],
        cardinality: MapCardinality,
    ) {
        let Self { body, params, .. } = self;

        match result.split_last() {
            None => {
                let object = synthesize(fields, &Value::Null, params);
                self.body = shape(vec![object], cardinality);
            }
            Some((field, parents)) => {
                for parent in parents_at_mut(body, parents) {
                    let child = synthesize(fields, parent, params);
                    let value = shape(vec![child], cardinality);
                    if let Value::Object(map) = parent {
                        map.insert(field.to_string(), value);
                    }
                }
            }
        }
    }

    fn tag_step(&mut self, result: &[&str], fields: &[(&str, ValueArg<'_>)]) {
        let Self { params, body, .. } = self;

        match result.split_last() {
            None => {
                let resolved = resolve_fields(fields, &Value::Null, params);
                for object in flatten_mut(body) {
                    set_fields(object, &resolved);
                }
            }
            Some((field, parents)) => {
                for parent in parents_at_mut(body, parents) {
                    let resolved = resolve_fields(fields, parent, params);
                    if let Some(slot) = parent.get_mut(*field) {
                        for object in flatten_mut(slot) {
                            set_fields(object, &resolved);
                        }
                    }
                }
            }
        }
    }

    fn key_step(
        &mut self,
        result: &[&str],
        database: &Database<'_>,
        segments: &[KeySegment<'_>],
        shard: &[(&str, ValueArg<'_>)],
    ) {
        let Self {
            storage,
            body,
            params,
            ..
        } = self;
        let (field, parents) = result
            .split_last()
            .expect("a key step attaches to a model field, never the root");

        for parent in parents_at_mut(body, parents) {
            let key = resolve_key(segments, parent, params);
            let value = read_key(database, shard, &key, parent, params, storage);

            if let Value::Object(map) = parent {
                map.insert(field.to_string(), value);
            }
        }
    }
}

/// Resolve each `(field, arg)` pair for a tag, dropping fields whose parent value is
/// absent (a designed absence) while a missing param stays a hard failure.
fn resolve_fields<'a>(
    fields: &[(&'a str, ValueArg<'_>)],
    parent: &Value,
    params: &Map<String, Value>,
) -> Vec<(&'a str, Value)> {
    let mut resolved = Vec::new();
    for (field, arg) in fields {
        match arg {
            ValueArg::Param(name) => {
                let value = params.get(*name).cloned().expect("Value to exist in tests");
                resolved.push((*field, value));
            }
            ValueArg::ParentField(name) => {
                if let Some(value) = parent.get(*name).cloned() {
                    resolved.push((*field, value));
                }
            }
        }
    }
    resolved
}

/// Set each resolved `(field, value)` on `object` when it is a JSON object.
fn set_fields(object: &mut Value, fields: &[(&str, Value)]) {
    if let Value::Object(map) = object {
        for (field, value) in fields {
            map.insert(field.to_string(), value.clone());
        }
    }
}

/// Read `key` from the storage named by `database`. Missing keys and unknown shards read
/// as `null` (storage exists implicitly). Shapes are schema-free, keyed by storage:
/// - R2 -> the raw stored value.
/// - KV -> `{ "value": v|null, "metadata": m|null }`.
/// - DO-KV -> the raw stored value.
fn read_key(
    database: &Database<'_>,
    shard: &[(&str, ValueArg<'_>)],
    key: &str,
    parent: &Value,
    params: &Map<String, Value>,
    storage: &MockStorage,
) -> Value {
    match &database.kind {
        DatabaseKind::R2 => storage
            .r2
            .get(database.name)
            .and_then(|bucket| bucket.get(key))
            .cloned()
            .expect("Value to exist in tests"),
        DatabaseKind::Kv => {
            let entry = storage.kv.get(database.name).and_then(|ns| ns.get(key));
            let (value, metadata) = entry
                .map(|(v, m)| (v.clone(), m.clone().unwrap_or(Value::Null)))
                .expect("Value to exist in tests");
            json!({ "value": value, "metadata": metadata })
        }
        DatabaseKind::DurableObject => {
            // A DO-KV read routes by its shard values, each sourced from a param (a
            // covered field) or the parent object's own field. A missing shard value
            // leaves the read unresolvable -> null.
            let tuple = shard
                .iter()
                .map(|(_, arg)| resolve_value_arg(arg, parent, params))
                .collect::<Vec<_>>();

            storage
                .durable_kv
                .get(database.name)
                .expect("Durable binding to exist in tests")
                .get(&tuple)
                .expect("Shard to exist in tests")
                .get(key)
                .expect("Value to exist in tests")
                .clone()
        }
        other => unreachable!("Key query routed at non-storage kind {other:?}"),
    }
}

fn resolve_key(segments: &[KeySegment<'_>], parent: &Value, params: &Map<String, Value>) -> String {
    let mut out = String::new();
    for segment in segments {
        match segment {
            KeySegment::Literal(text) => out.push_str(text),
            KeySegment::Value(arg) => match resolve_value_arg(arg, parent, params) {
                Value::String(s) => out.push_str(&s),
                other => out.push_str(&other.to_string()),
            },
        }
    }
    out
}

fn resolve_value_arg(arg: &ValueArg<'_>, parent: &Value, params: &Map<String, Value>) -> Value {
    match arg {
        ValueArg::Param(name) => params.get(*name).cloned(),
        ValueArg::ParentField(name) => parent.get(*name).cloned(),
    }
    .expect("Value to exist in tests")
}

fn synthesize(
    fields: &[(&str, ValueArg<'_>)],
    parent: &Value,
    params: &Map<String, Value>,
) -> Value {
    let mut map = Map::new();
    for (field, arg) in fields {
        let value = match arg {
            ValueArg::Param(name) => {
                Some(params.get(*name).cloned().expect("Value to exist in tests"))
            }
            ValueArg::ParentField(name) => parent.get(*name).cloned(),
        }
        .expect("Value to exist in tests");

        map.insert(field.to_string(), value);
    }
    Value::Object(map)
}

fn shard_tuples(
    shard: &[(&str, SqlArg<'_>)],
    params: &Map<String, Value>,
    body: &Value,
    parents: &[&str],
) -> Vec<Vec<Value>> {
    if shard.is_empty() {
        return vec![vec![]];
    }

    let columns = shard
        .iter()
        .map(|(_, arg)| resolve(arg, params, body, parents))
        .collect::<Vec<_>>();
    let len = columns.iter().map(|c| c.len()).max().unwrap_or(0);
    dedup(
        (0..len)
            .map(|i| {
                columns
                    .iter()
                    .map(|c| c.get(i).cloned().unwrap_or(Value::Null))
                    .collect()
            })
            .collect(),
    )
}

/// Execute `sql` against `pool`: resolve each `?N` slot from `bindings[N-1]`, expand
/// every spread fully, and return the rows.
///
/// We would chunk large spreads here in the  actual runtime
/// (to stay under the storage's bind-parameter limit)
async fn run_sql(
    sql: &str,
    bindings: &[SqlArg<'_>],
    params: &Map<String, Value>,
    body: &Value,
    parents: &[&str],
    pool: &SqlitePool,
) -> Vec<Value> {
    let slots = bindings
        .iter()
        .map(|b| resolve(b, params, body, parents))
        .collect::<Vec<_>>();

    // An empty `IN ()` matches nothing, so a spread with no values short-circuits.
    if slots.iter().any(|s| s.is_empty()) {
        return Vec::new();
    }

    query_rows(&expand(sql, &slots), &slots.concat(), pool).await
}

/// Resolve a [SqlArg] to the value(s) occupying its `?N` slot: a `Param` is single-valued,
/// a `Spread` yields every value of its field across the parents of the step's own result
/// (`parents` + field), deduped with nulls dropped.
fn resolve(
    binding: &SqlArg<'_>,
    params: &Map<String, Value>,
    body: &Value,
    parents: &[&str],
) -> Vec<Value> {
    match binding {
        SqlArg::Param(name) => params
            .get(*name)
            .cloned()
            .map(|v| vec![v])
            .expect("Value to exist in tests"),

        SqlArg::Spread(field) => dedup(spread_at(body, parents, field)),
    }
}

/// Every non-null value of `field` across the parents at `parents` (`parents` + field).
fn spread_at(body: &Value, parents: &[&str], field: &str) -> Vec<Value> {
    let path = parents.iter().copied().chain([field]).collect::<Vec<_>>();
    collect_at(body, &path)
}

fn dedup<T: PartialEq>(values: Vec<T>) -> Vec<T> {
    values.into_iter().fold(Vec::new(), |mut out, v| {
        if !out.contains(&v) {
            out.push(v);
        }
        out
    })
}

/// Replace each `?N` with one plain `?` per value in `slots[N-1]`. Placeholders appear
/// in ascending order in planner SQL, so anonymous `?`s bind in flattened slot order.
/// Highest index first, so replacing `?1` never clobbers the prefix of `?10`.
fn expand(sql: &str, slots: &[Vec<Value>]) -> String {
    slots
        .iter()
        .enumerate()
        .rev()
        .fold(sql.to_string(), |sql, (i, values)| {
            sql.replace(&format!("?{}", i + 1), &vec!["?"; values.len()].join(", "))
        })
}

async fn query_rows(sql: &str, binds: &[Value], pool: &SqlitePool) -> Vec<Value> {
    let query = binds.iter().fold(sqlx::query(sql), |q, v| match v {
        Value::Null => q.bind(None::<String>),
        Value::Bool(b) => q.bind(*b as i64),
        Value::Number(n) if n.is_i64() => q.bind(n.as_i64().unwrap()),
        Value::Number(n) => q.bind(n.as_f64().unwrap()),
        Value::String(s) => q.bind(s.clone()),
        other => q.bind(other.to_string()),
    });
    let rows = query
        .fetch_all(pool)
        .await
        .expect("Query to succeed in tests");

    rows.iter().map(row_to_json).collect()
}

/// Convert a raw SQLite row into a JSON object keyed by column name. `try_get`
/// type-checks (but decodes NULL as a zero value, hence the explicit null check),
/// so falling through i64 -> f64 -> String is safe.
fn row_to_json(row: &sqlx::sqlite::SqliteRow) -> Value {
    Value::Object(
        row.columns()
            .iter()
            .map(|c| {
                let i = c.ordinal();
                let value = if row.try_get_raw(i).map(|r| r.is_null()).unwrap_or(true) {
                    Value::Null
                } else {
                    row.try_get::<i64, _>(i)
                        .map(Value::from)
                        .or_else(|_| row.try_get::<f64, _>(i).map(Value::from))
                        .or_else(|_| row.try_get::<String, _>(i).map(Value::from))
                        .expect("Column type to be supported in tests")
                };
                (c.name().to_string(), value)
            })
            .collect(),
    )
}

/// Every non-null value at `path` across the hydrated body, flattening through arrays.
fn collect_at(body: &Value, path: &[&str]) -> Vec<Value> {
    path.iter()
        .fold(vec![body], |current, key| {
            current
                .into_iter()
                .flat_map(flatten)
                .filter_map(|v| v.get(*key))
                .collect()
        })
        .into_iter()
        .flat_map(flatten)
        .filter(|v| !v.is_null())
        .cloned()
        .collect()
}

/// Expand arrays into their elements; scalars/objects pass through as a single item.
fn flatten(value: &Value) -> Vec<&Value> {
    match value {
        Value::Array(items) => items.iter().flat_map(flatten).collect(),
        other => vec![other],
    }
}

/// Attach `rows` at `result`: a root step's rows become the body itself; a nav
/// step's rows are joined under the final path segment of every parent they match.
fn attach_rows(body: &mut Value, result: &[&str], mapping: &Mapping<'_>, rows: Vec<Value>) {
    match result.split_last() {
        None => *body = shape(rows, mapping.cardinality),
        Some((field, parents)) => {
            for parent in parents_at_mut(body, parents) {
                let matched = rows
                    .iter()
                    .filter(|row| join(parent, row, &mapping.join))
                    .cloned()
                    .collect();
                if let Value::Object(map) = parent {
                    map.insert(field.to_string(), shape(matched, mapping.cardinality));
                }
            }
        }
    }
}

fn shape(rows: Vec<Value>, cardinality: MapCardinality) -> Value {
    match cardinality {
        MapCardinality::One => rows.into_iter().next().unwrap_or(Value::Null),
        MapCardinality::Many => Value::Array(rows),
    }
}

/// True if `row` belongs on `parent`: every pair must satisfy
/// `parent[parent_key] == row[child_key]`. An empty join matches every parent.
fn join(parent: &Value, row: &Value, keys: &[JoinKeys]) -> bool {
    keys.iter().all(|pair| {
        matches!(
            (parent.get(pair.parent_key), row.get(pair.child_key)),
            (Some(a), Some(b)) if a == b
        )
    })
}

/// Mutable references to every object reached by following `path` through the body,
/// flattening through arrays.
fn parents_at_mut<'a>(body: &'a mut Value, path: &[&str]) -> Vec<&'a mut Value> {
    path.iter()
        .fold(vec![body], |current, key| {
            current
                .into_iter()
                .flat_map(flatten_mut)
                .filter_map(|v| v.get_mut(*key))
                .collect()
        })
        .into_iter()
        .flat_map(flatten_mut)
        .collect()
}

fn flatten_mut(value: &mut Value) -> Vec<&mut Value> {
    match value {
        Value::Array(items) => items.iter_mut().flat_map(flatten_mut).collect(),
        other => vec![other],
    }
}
